class AnimatedCircle(FloatLayout):
    """Animated background circle widget"""
    duration = NumericProperty(2)
    delay = NumericProperty(0)
    color = ListProperty([0.38, 0.23, 0.89, 0.2])  # violet/20
    
    def on_parent(self, *args):
        anim = Animation(opacity=0.3, duration=self.duration)
        anim &= Animation(scale=1.2, duration=self.duration)
        anim.on_complete = lambda *_: self._reverse_animation()
        Clock.schedule_once(lambda dt: anim.start(self), self.delay)
    
    def _reverse_animation(self):
        anim = Animation(opacity=0.6, duration=self.duration)
        anim &= Animation(scale=1, duration=self.duration)
        anim.on_complete = lambda *_: self._animate()
        anim.start(self)


class LoadingScreen(MDScreen):
    """Animated loading/splash screen"""
    
    # Theme colors - matching web design
    primary_color = ListProperty([0.58, 0.45, 0.95, 1])  # violet-500
    accent_color = ListProperty([0.96, 0.26, 0.21, 1])   # fuchsia-500
    secondary_color = ListProperty([0.76, 0.33, 0.77, 1]) # purple-500
    background_color = ListProperty([0.05, 0.05, 0.11, 1]) # slate-950
    surface_color = ListProperty([0.15, 0.15, 0.23, 1])  # slate-800/60
    emerald_color = ListProperty([0.16, 0.71, 0.45, 1])  # emerald-500
    
    def on_enter(self):
        """Start loading animation"""
        self.animate_progress()
    
    def animate_progress(self):
        """Animate progress bar with status messages"""
        status_messages = [
            'Initializing...',
            'Loading AI models...',
            'Preparing video engine...',
            'Connecting to GPU...',
            'Almost ready...',
            'Ready!'
        ]
        
        progress = 0
        status_index = 0
        
        def update_progress(dt):
            nonlocal progress, status_index
            
            if progress < 100:
                progress += 5
                self.ids.progress_bar.value = progress
                
                # Update status based on progress
                new_index = int(progress / 17)
                if new_index != status_index and new_index < len(status_messages):
                    status_index = new_index
                    self.ids.status_text.text = status_messages[status_index]
                
                Clock.schedule_once(update_progress, 0.1)
            else:
                # Loading complete, go to home
                Clock.schedule_once(lambda dt: self.go_to_home(), 0.5)
        
        Clock.schedule_once(update_progress, 0.5)
    
    def go_to_home(self):
        """Navigate to home screen"""
        self.manager.current = 'home'


